static common_chat_params common_chat_params_init_mistral_instruct_v3(const common_chat_template &          tmpl,
                                                                      const autoparser::generation_params & inputs) {
    (void) tmpl;
    common_chat_params data;

    std::string sys;
    bool        first_user = true;

    for (const auto & msg : inputs.messages) {
        const std::string role    = msg.value("role", "");
        const std::string content = msg.value("content", "");

        if (role == "system") {
            sys = content;
        } else if (role == "user") {
            if (first_user) {
                first_user = false;
                if (!sys.empty()) {
                    data.prompt += "<s>[INST] " + sys + "\n" + content + " [/INST]";
                } else {
                    data.prompt += "<s>[INST] " + content + " [/INST]";
                }
            } else {
                data.prompt += "[INST] " + content + " [/INST]";
            }
        } else if (role == "assistant") {
            data.prompt += " " + content + "</s>";
        }
    }

    data.format = COMMON_CHAT_FORMAT_CONTENT_ONLY;
    return data;
}

